func TestValidateRappiPathSlug(t *testing.T) {
	for _, valid := range []string{"ciudad-de-mexico", "sushi", "rappimall-parent", "10000295-el-farolito"} {
		if err := validateRappiPathSlug("slug", valid); err != nil {
			t.Fatalf("validateRappiPathSlug(%q): %v", valid, err)
		}
	}
	for _, invalid := range []string{"../secret", "Ciudad-De-Mexico", "sushi/menu", "market?x=1", ""} {
		err := validateRappiPathSlug("slug", invalid)
		if err == nil {
			t.Fatalf("validateRappiPathSlug(%q) succeeded, want error", invalid)
		}
		if invalid != "" && !strings.Contains(err.Error(), "lowercase letters, numbers, and hyphens") {
			t.Fatalf("unexpected error for %q: %v", invalid, err)
		}
	}
}

func TestStoresAdjacencyRequiresFetchDetail(t *testing.T) {
	cmd := newStoresAdjacencyCmd(&rootFlags{})
	cmd.SilenceUsage = true
	err := cmd.Execute()
	if err == nil {
		t.Fatal("expected stores adjacency to require --fetch-detail")
	}
	if !strings.Contains(err.Error(), "--fetch-detail is required") {
		t.Fatalf("unexpected error: %v", err)
	}
}
